23	func (s *FinanceService) CreateBudget(clubID int64, accountCode, campusCode, projectCode, periodType, periodStart string, amount float64, userID int64) (int64, error) {
24		if amount <= 0 {
25			return 0, errors.New("amount must be positive")
26		}
27		if strings.TrimSpace(accountCode) == "" {
28			return 0, errors.New("account_code required")
29		}
30		if strings.TrimSpace(campusCode) == "" {
31			return 0, errors.New("campus_code required")
32		}
33		if strings.TrimSpace(projectCode) == "" {
34			return 0, errors.New("project_code required")
35		}
36		if periodType != "monthly" && periodType != "quarterly" {
37			return 0, errors.New("period_type must be monthly or quarterly")
38		}
39		if err := validateBudgetPeriodStart(periodType, periodStart); err != nil {
40			return 0, err
41		}
42		return s.store.InsertBudget(models.Budget{
43			ClubID:      clubID,
44			AccountCode: accountCode,
45			CampusCode:  campusCode,
46			ProjectCode: projectCode,
47			PeriodType:  periodType,
48			PeriodStart: periodStart,
49			Amount:      amount,
50			Spent:       0,
51			CreatedBy:   userID,
52			Status:      "active",
53		})
54	}
55	
56	func validateBudgetPeriodStart(periodType, periodStart string) error {
57		monthlyPattern := regexp.MustCompile(`^\d{4}-(0[1-9]|1[0-2])$`)
58		quarterlyPattern := regexp.MustCompile(`^\d{4}-Q[1-4]$`)
59		if periodType == "monthly" && !monthlyPattern.MatchString(periodStart) {
60			return errors.New("period_start must be YYYY-MM for monthly")
61		}
62		if periodType == "quarterly" && !quarterlyPattern.MatchString(periodStart) {
63			return errors.New("period_start must be YYYY-Q[1-4] for quarterly")
64		}
65		return nil
66	}
