68	func (s *FinanceService) RequestBudgetChange(budgetID, requesterID int64, proposedAmount float64, reason string, requesterRole string, requesterClubID *int64) (int64, error) {
69		b, err := s.store.GetBudgetByID(budgetID)
70		if err != nil {
71			return 0, err
72		}
73		if requesterRole == "team_lead" {
74			if requesterClubID == nil {
75				return 0, errors.New("team lead missing club assignment")
76			}
77			if *requesterClubID != b.ClubID {
78				return 0, errors.New("forbidden by club scope")
79			}
80		}
81		if requesterRole != "admin" && requesterRole != "organizer" && requesterRole != "team_lead" {
82			return 0, errors.New("insufficient role")
83		}
84		if b.Amount == 0 {
85			return 0, errors.New("budget amount cannot be zero")
86		}
87		if proposedAmount <= 0 {
88			return 0, errors.New("proposed amount must be positive")
89		}
90		changePct := math.Abs((proposedAmount - b.Amount) / b.Amount * 100)
91		if changePct <= 10 {
92			if _, err := s.store.DB.Exec(`UPDATE budgets SET amount = ? WHERE id = ?`, proposedAmount, budgetID); err != nil {
93				return 0, err
94			}
95			return 0, nil
96		}
97		if requesterRole != "organizer" {
98			return 0, errors.New("requester must be organizer for >10% changes")
99		}
100		return s.store.InsertBudgetChangeRequest(models.BudgetChangeRequest{
101			BudgetID:       budgetID,
102			RequestedBy:    requesterID,
103			ProposedAmount: proposedAmount,
104			ChangePercent:  changePct,
105			Reason:         reason,
106			Status:         "pending",
107		})
108	}
