118	func (s *FinanceService) RecordSpend(budgetID int64, spent float64) error {
119		if spent < 0 {
120			return errors.New("spent must be non-negative")
121		}
122		budget, err := s.store.GetBudgetByID(budgetID)
123		if err != nil {
124			return err
125		}
126		if err := s.store.UpdateBudgetSpent(budgetID, spent); err != nil {
127			return err
128		}
129		alert := budget.Amount > 0 && (spent/budget.Amount) >= 0.85
130		return s.store.UpdateBudgetThreshold(budgetID, alert)
131	}
132	
133	func (s *FinanceService) ApproveChange(changeID, adminID int64, approve bool, reviewerRole string) error {
134		if reviewerRole != "admin" {
135			return errors.New("reviewer must be admin")
136		}
137		requesterID, err := s.store.GetBudgetChangeRequester(changeID)
138		if err != nil {
139			return err
140		}
141		if requesterID == adminID {
142			return errors.New("reviewer must differ from requester")
143		}
144		requester, err := s.store.FindUserByID(requesterID)
145		if err != nil {
146			return err
147		}
148		if requester.Role != "organizer" {
149			return errors.New("requester must be organizer")
150		}
151		reviewer, err := s.store.FindUserByID(adminID)
152		if err != nil {
153			return err
154		}
155		if reviewer.Role != "admin" {
156			return errors.New("reviewer must be admin")
157		}
158		return s.store.ApproveBudgetChange(changeID, adminID, approve)
159	}
