161	func (s *FinanceService) StartThresholdWorker(every time.Duration) {
162		ticker := time.NewTicker(every)
163		defer ticker.Stop()
164		for range ticker.C {
165			_ = s.RefreshThresholdAlerts()
166		}
167	}
168	
169	func (s *FinanceService) RefreshThresholdAlerts() error {
170		budgets, err := s.store.ListBudgets(nil)
171		if err != nil {
172			return err
173		}
174		for _, b := range budgets {
175			alert := b.Amount > 0 && (b.Spent/b.Amount) >= 0.85
176			if alert != b.ThresholdAlert {
177				if err := s.store.UpdateBudgetThreshold(b.ID, alert); err != nil {
178					return err
179				}
180				before := map[string]any{"threshold_alert": b.ThresholdAlert}
181				after := map[string]any{"threshold_alert": alert}
182				_ = s.store.InsertAuditLog(nil, "WORKER", "/workers/budget-thresholds", "budgets", strconv.FormatInt(b.ID, 10), before, after)
183			}
184		}
185		return nil
186	}
187	
188	func (s *FinanceService) Projection(b models.Budget, expectedRemainingSpend float64) float64 {
189		return b.Amount - (b.Spent + expectedRemainingSpend)
190	}
