10	func (s *SQLiteStore) InsertBudget(b models.Budget) (int64, error) {
11		res, err := s.DB.Exec(`INSERT INTO budgets (club_id, account_code, campus_code, project_code, period_type, period_start, amount, spent, created_by, status) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?)`,
12			b.ClubID, b.AccountCode, b.CampusCode, b.ProjectCode, b.PeriodType, b.PeriodStart, b.Amount, b.Spent, b.CreatedBy, b.Status)
13		if err != nil {
14			return 0, err
15		}
16		return res.LastInsertId()
17	}
