19	func (s *SQLiteStore) ListBudgets(clubID *int64) ([]models.Budget, error) {
20		query := `SELECT id, club_id, account_code, campus_code, project_code, period_type, period_start, amount, spent, threshold_alert, created_by, status, created_at FROM budgets`
21		args := []any{}
22		if clubID != nil {
23			query += ` WHERE club_id = ?`
24			args = append(args, *clubID)
25		}
26		query += ` ORDER BY created_at DESC`
27		rows, err := s.DB.Query(query, args...)
28		if err != nil {
29			return nil, err
30		}
31		defer rows.Close()
32		out := []models.Budget{}
33		for rows.Next() {
34			var b models.Budget
35			var threshold int
36			if err := rows.Scan(&b.ID, &b.ClubID, &b.AccountCode, &b.CampusCode, &b.ProjectCode, &b.PeriodType, &b.PeriodStart, &b.Amount, &b.Spent, &threshold, &b.CreatedBy, &b.Status, &b.CreatedAt); err != nil {
37				return nil, err
38			}
39			b.ThresholdAlert = threshold == 1
40			out = append(out, b)
41		}
42		return out, nil
43	}
