45	func (s *SQLiteStore) GetBudgetByID(id int64) (*models.Budget, error) {
46		var b models.Budget
47		var threshold int
48		err := s.DB.QueryRow(`SELECT id, club_id, account_code, campus_code, project_code, period_type, period_start, amount, spent, threshold_alert, created_by, status, created_at FROM budgets WHERE id = ?`, id).
49			Scan(&b.ID, &b.ClubID, &b.AccountCode, &b.CampusCode, &b.ProjectCode, &b.PeriodType, &b.PeriodStart, &b.Amount, &b.Spent, &threshold, &b.CreatedBy, &b.Status, &b.CreatedAt)
50		if err != nil {
51			return nil, err
52		}
53		b.ThresholdAlert = threshold == 1
54		return &b, nil
55	}
