67	func (s *SQLiteStore) InsertBudgetChangeRequest(r models.BudgetChangeRequest) (int64, error) {
68		res, err := s.DB.Exec(`INSERT INTO budget_change_requests (budget_id, requested_by, proposed_amount, change_percent, reason, status) VALUES (?, ?, ?, ?, ?, ?)`,
69			r.BudgetID, r.RequestedBy, r.ProposedAmount, r.ChangePercent, r.Reason, r.Status)
70		if err != nil {
71			return 0, err
72		}
73		return res.LastInsertId()
