76	func (s *SQLiteStore) ListPendingBudgetChanges(clubID *int64) ([]models.BudgetChangeRequest, error) {
77		query := `SELECT bcr.id, bcr.budget_id, bcr.requested_by, bcr.proposed_amount, bcr.change_percent, bcr.reason, bcr.status, bcr.reviewed_by, bcr.created_at
78			FROM budget_change_requests bcr
79			JOIN budgets b ON b.id = bcr.budget_id
80			WHERE bcr.status = 'pending'`
81		args := []any{}
82		if clubID != nil {
83			query += ` AND b.club_id = ?`
84			args = append(args, *clubID)
85		}
86		query += ` ORDER BY bcr.created_at DESC`
87		rows, err := s.DB.Query(query, args...)
88		if err != nil {
89			return nil, err
90		}
91		defer rows.Close()
92		out := []models.BudgetChangeRequest{}
93		for rows.Next() {
94			var it models.BudgetChangeRequest
95			var reviewed sql.NullInt64
96			if err := rows.Scan(&it.ID, &it.BudgetID, &it.RequestedBy, &it.ProposedAmount, &it.ChangePercent, &it.Reason, &it.Status, &reviewed, &it.CreatedAt); err != nil {
97				return nil, err
98			}
99			if reviewed.Valid {
100				it.ReviewedBy = &reviewed.Int64
101			}
102			out = append(out, it)
103		}
104		return out, nil
105	}
