107	func (s *SQLiteStore) GetBudgetChangeRequester(changeID int64) (int64, error) {
108		var requesterID int64
109		if err := s.DB.QueryRow(`SELECT requested_by FROM budget_change_requests WHERE id = ?`, changeID).Scan(&requesterID); err != nil {
110			return 0, err
111		}
112		return requesterID, nil
113	}
