115	func (s *SQLiteStore) ApproveBudgetChange(changeID, adminID int64, approve bool) error {
116		tx, err := s.DB.Begin()
117		if err != nil {
118			return err
119		}
120		defer tx.Rollback()
121	
122		var budgetID int64
123		var amount float64
124		var requesterID int64
125		var requesterRole string
126		var reviewerRole string
127		if err := tx.QueryRow(`SELECT bcr.budget_id, bcr.proposed_amount, bcr.requested_by, requester.role, reviewer.role
128			FROM budget_change_requests bcr
129			JOIN users requester ON requester.id = bcr.requested_by
130			JOIN users reviewer ON reviewer.id = ?
131			WHERE bcr.id = ? AND bcr.status = 'pending'`, adminID, changeID).Scan(&budgetID, &amount, &requesterID, &requesterRole, &reviewerRole); err != nil {
132			return err
133		}
134		if requesterID == adminID {
135			return errors.New("reviewer must differ from requester")
136		}
137		if requesterRole != "organizer" {
138			return errors.New("requester must be organizer")
139		}
140		if reviewerRole != "admin" {
141			return errors.New("reviewer must be admin")
142		}
143		status := "rejected"
144		if approve {
145			status = "approved"
146			if _, err := tx.Exec(`UPDATE budgets SET amount = ? WHERE id = ?`, amount, budgetID); err != nil {
147				return err
148			}
149		}
150		if _, err := tx.Exec(`UPDATE budget_change_requests SET status = ?, reviewed_by = ? WHERE id = ?`, status, adminID, changeID); err != nil {
151			return err
152		}
153		return tx.Commit()
154	}
155	
156	func (s *SQLiteStore) CanAccessBudget(user *models.User, budgetID int64) (bool, error) {
157		b, err := s.GetBudgetByID(budgetID)
158		if err != nil {
159			return false, err
160		}
161		if user.Role != "admin" {
162			if user.Role == "member" {
163				return false, nil
164			}
165			if user.ClubID == nil {
166				return false, errors.New("club scope required")
167			}
168			if user.ClubID != nil && b.ClubID != *user.ClubID {
169				return false, nil
170			}
171		}
172		return true, nil
173	}
