16	func (h *Handler) createReview(c *fiber.Ctx) error {
17		user := currentUser(c)
18		if user != nil && (user.Role == "organizer" || user.Role == "team_lead") && user.ClubID == nil {
19			return apiError(c, fiber.StatusForbidden, "club_scope_required", "club scope required")
20		}
21		orderID, err := strconv.ParseInt(c.FormValue("fulfilled_order_id"), 10, 64)
22		if err != nil {
23			return apiError(c, fiber.StatusBadRequest, "validation_error", "invalid fulfilled_order_id")
24		}
25		order, err := h.store.GetFulfilledOrderByID(orderID)
26		if err != nil {
27			return h.writeServiceError(c, err)
28		}
29		if user.Role == "member" && order.OwnerUserID != user.ID {
30			return apiError(c, fiber.StatusForbidden, "forbidden", "You are not allowed to perform this action.")
31		}
32		if user.ClubID != nil && *user.ClubID != order.ClubID {
33			return apiError(c, fiber.StatusForbidden, "forbidden", "You are not allowed to perform this action.")
34		}
35		stars, err := strconv.Atoi(c.FormValue("stars"))
36		if err != nil {
37			return apiError(c, fiber.StatusBadRequest, "validation_error", "invalid stars")
38		}
39		form, err := c.MultipartForm()
40		if err != nil {
41			return apiError(c, fiber.StatusBadRequest, "bad_request", "Request could not be processed.")
42		}
43		var files []*multipart.FileHeader
44		if form != nil && form.File != nil {
45			files = form.File["images"]
46		}
47		tags := strings.Split(c.FormValue("tags"), ",")
48		_, err = h.review.CreateReviewForOrder(orderID, user.ID, stars, tags, c.FormValue("comment"), files)
49		if err != nil {
50			return h.writeServiceError(c, err)
51		}
52		c.Set("HX-Trigger", `{"reviewsUpdated":true}`)
53		return c.SendString("review submitted")
54	}
