56	func (h *Handler) createFulfilledOrder(c *fiber.Ctx) error {
57		user := currentUser(c)
58		if user == nil {
59			return apiError(c, fiber.StatusUnauthorized, "unauthorized", "Authentication required.")
60		}
61		if user.Role == "member" {
62			return apiError(c, fiber.StatusForbidden, "forbidden", "You are not allowed to perform this action.")
63		}
64		var clubID int64
65		if user.Role == "admin" {
66			parsed, err := strconv.ParseInt(strings.TrimSpace(c.FormValue("club_id")), 10, 64)
67			if err != nil {
68				return apiError(c, fiber.StatusBadRequest, "validation_error", "invalid club_id")
69			}
70			clubID = parsed
71		} else {
72			if user.ClubID == nil {
73				return apiError(c, fiber.StatusForbidden, "club_scope_required", "club scope required")
74			}
75			clubID = *user.ClubID
76		}
77		siteID, err := strconv.ParseInt(c.FormValue("site_id"), 10, 64)
78		if err != nil {
79			return apiError(c, fiber.StatusBadRequest, "validation_error", "invalid site_id")
80		}
81		memberID, err := strconv.ParseInt(c.FormValue("member_id"), 10, 64)
82		if err != nil {
83			return apiError(c, fiber.StatusBadRequest, "validation_error", "invalid member_id")
84		}
85		member, err := h.store.GetMemberByID(memberID)
86		if err != nil {
87			return h.writeServiceError(c, err)
88		}
89		if member.ClubID != clubID {
90			return apiError(c, fiber.StatusForbidden, "forbidden", "member must belong to selected club")
91		}
92		serviceLabel := strings.TrimSpace(c.FormValue("service_label"))
93		if serviceLabel == "" {
94			return apiError(c, fiber.StatusBadRequest, "validation_error", "service_label required")
95		}
96		fulfilledAt := time.Now()
97		if raw := strings.TrimSpace(c.FormValue("fulfilled_at")); raw != "" {
98			parsed, err := time.Parse(time.RFC3339, raw)
99			if err != nil {
100				return apiError(c, fiber.StatusBadRequest, "validation_error", "fulfilled_at must be RFC3339")
101			}
102			fulfilledAt = parsed
103		}
104		id, err := h.store.InsertFulfilledOrder(models.FulfilledOrder{
105			ClubID:       clubID,
106			SiteID:       siteID,
107			MemberID:     memberID,
108			OwnerUserID:  user.ID,
109			ServiceLabel: serviceLabel,
110			Status:       "fulfilled",
111			FulfilledAt:  fulfilledAt,
112		})
113		if err != nil {
114			return h.writeServiceError(c, err)
115		}
116		c.Set("HX-Trigger", `{"fulfilledOrdersUpdated":true}`)
117		return c.SendString("fulfilled order recorded #" + strconv.FormatInt(id, 10))
118	}
