139	func (h *Handler) importMembersCSV(c *fiber.Ctx) error {
140		user := currentUser(c)
141		if err := requireManagedClub(user); err != nil {
142			return apiError(c, fiber.StatusForbidden, "forbidden", "You are not allowed to perform this action.")
143		}
144		fh, err := c.FormFile("file")
145		if err != nil {
146			return apiError(c, fiber.StatusBadRequest, "validation_error", "file required")
147		}
148		f, err := fh.Open()
149		if err != nil {
150			return apiError(c, fiber.StatusBadRequest, "bad_request", "Request could not be processed.")
151		}
152		defer f.Close()
153		r := csv.NewReader(f)
154		header, err := r.Read()
155		if err != nil {
156			if err == io.EOF {
157				return apiError(c, fiber.StatusBadRequest, "validation_error", "csv empty")
158			}
159			return apiError(c, fiber.StatusBadRequest, "bad_request", "Request could not be processed.")
160		}
161		hasLeadingID, err := validateMemberImportHeader(header)
162		if err != nil {
163			return apiError(c, fiber.StatusUnprocessableEntity, "validation_error", err.Error())
164		}
165		rowNum := 1
166		inserted := 0
167		errorsOut := [][]string{{"row", "error"}}
168		var clubID int64
169		if user.Role == "admin" {
170			parsed, err := strconv.ParseInt(strings.TrimSpace(c.FormValue("club_id")), 10, 64)
171			if err != nil {
172				return apiError(c, fiber.StatusBadRequest, "validation_error", "invalid club_id")
173			}
174			clubID = parsed
175		} else {
176			if user.ClubID == nil {
177				return apiError(c, fiber.StatusForbidden, "club_scope_required", "club scope required")
178			}
179			clubID = *user.ClubID
180		}
181		for {
182			row, err := r.Read()
183			if err != nil {
184				if err == io.EOF {
185					break
186				}
187				return apiError(c, fiber.StatusBadRequest, "bad_request", "Request could not be processed.")
188			}
189			rowNum++
190			if rowNum > 5001 {
191				errorsOut = append(errorsOut, []string{strconv.Itoa(rowNum), "row limit exceeded (5000)"})
192				break
193			}
194			memberRow, err := parseMemberImportRow(row, hasLeadingID)
195			if err != nil {
196				errorsOut = append(errorsOut, []string{strconv.Itoa(rowNum), err.Error()})
197				continue
198			}
199			if err := validateMemberCoreFields(memberRow[0], memberRow[1], memberRow[2], memberRow[3]); err != nil {
200				errorsOut = append(errorsOut, []string{strconv.Itoa(rowNum), err.Error()})
201				continue
202			}
203			custom := memberRow[7]
204			if custom == "" {
205				custom = "{}"
206			}
207			if !json.Valid([]byte(custom)) {
208				errorsOut = append(errorsOut, []string{strconv.Itoa(rowNum), "invalid custom_fields json"})
209				continue
210			}
211			isActive := strings.ToLower(strings.TrimSpace(memberRow[5])) != "false"
212			_, err = h.store.InsertMember(models.Member{ClubID: clubID, FullName: memberRow[0], EmailEncrypted: h.crypto.Encrypt(memberRow[1]), PhoneEncrypted: h.crypto.Encrypt(memberRow[2]), JoinDate: memberRow[3], PositionTitle: memberRow[4], IsActive: isActive, GroupName: memberRow[6], CustomFields: h.encryptCustomFields(custom)})
213			if err != nil {
214				errorsOut = append(errorsOut, []string{strconv.Itoa(rowNum), err.Error()})
215				continue
216			}
217			inserted++
218		}
219		if rowNum == 1 {
220			return apiError(c, fiber.StatusBadRequest, "validation_error", "csv empty")
221		}
222		if len(errorsOut) > 1 {
223			var b strings.Builder
224			w := csv.NewWriter(&b)
225			for _, rec := range errorsOut {
226				_ = w.Write(rec)
227			}
228			w.Flush()
229			reportCSV := b.String()
230			if c.Get("HX-Request") == "true" {
231				reportPath, err := saveMemberImportErrorReport(reportCSV)
232				if err != nil {
233					return h.writeServiceError(c, err)
234				}
235				return c.Status(422).SendString(`<div class="rounded border border-amber-300 bg-amber-50 px-3 py-2 text-amber-800">Import completed with row errors. <a class="underline font-medium" href="` + reportPath + `" download>Download error report CSV</a></div>`)
236			}
237			c.Set("Content-Type", "text/csv")
238			c.Set("Content-Disposition", "attachment; filename=member_import_errors.csv")
239			return c.Status(422).SendString(reportCSV)
240		}
241		return c.SendString("members imported: " + strconv.Itoa(inserted))
242	}
